import { createRouter, createWebHistory } from "vue-router";
import HtmlView from "../components/HtmlView.vue";

const routes = [
  // páginas principais
  { path: "/", component: HtmlView, props: { file: "/src/assets/html/home.html" } },
  { path: "/sobre", component: HtmlView, props: { file: "/src/assets/html/sobre.html" } },
  { path: "/educacao", component: HtmlView, props: { file: "/src/assets/html/educacao.html" } },
  { path: "/analises", component: HtmlView, props: { file: "/src/assets/html/analises.html" } },
  { path: "/publicacoes", component: HtmlView, props: { file: "/src/assets/html/publicacoes.html" } },

  // admin
  { path: "/admin/login", component: HtmlView, props: { file: "/src/assets/html/admin/adminlogin.html" } },
  { path: "/admin/dashboard", component: HtmlView, props: { file: "/src/assets/html/admin/admindashboard.html" } },

  // paineis
  { path: "/paineis/atividade-policial", component: HtmlView, props: { file: "/src/assets/html/paineis/atividade-policial.html" } },
  { path: "/paineis/crimes-economicos", component: HtmlView, props: { file: "/src/assets/html/paineis/crimes-economicos.html" } },
  { path: "/paineis/homicidios", component: HtmlView, props: { file: "/src/assets/html/paineis/homicidios.html" } },
  { path: "/paineis/populacao-ibge", component: HtmlView, props: { file: "/src/assets/html/paineis/populacao_ibge.html" } },
  { path: "/paineis/sistema-justica", component: HtmlView, props: { file: "/src/assets/html/paineis/sistema-justica.html" } },
  { path: "/paineis/violencia-genero", component: HtmlView, props: { file: "/src/assets/html/paineis/violencia-genero.html" } },
  { path: "/paineis/vitimizacao", component: HtmlView, props: { file: "/src/assets/html/paineis/vitimizacao.html" } },
];

const router = createRouter({
  history: createWebHistory(),
  routes,
});

export default router;
